User stories: [{"id": "US1", "description": "Jako nowy użytkownik chcę zarejestrować konto w systemie podając adres e-mail, hasło i dane osobowe, aby móc korzystać z funkcji rezerwacji wizyt."}, {"id": "US2", "description": "Jako zarejestrowany użytkownik chcę zalogować się do systemu przy użyciu adresu e-mail i hasła, aby uzyskać dostęp do funkcji przypisanych do mojej roli."}, {"id": "US3", "description": "Jako pacjent chcę przeglądać listę dostępnych terminów wizyt z możliwością filtrowania według specjalizacji, specjalisty, daty i godziny, aby szybko znaleźć odpowiedni termin."}, {"id": "US4", "description": "Jako pacjent chcę wyszukać specjalistę po imieniu, nazwisku lub specjalizacji, aby zobaczyć jego profil i dostępne terminy wizyt."}, {"id": "US5", "description": "Jako pacjent chcę zarezerwować wybrany termin u wybranego specjalisty, aby potwierdzić swoją wizytę w systemie."}, {"id": "US6", "description": "Jako pacjent chcę anulować moją rezerwację wizyty z odpowiednim wyprzedzeniem czasowym, aby zwolnić termin i uniknąć konsekwencji późnego odwołania."}, {"id": "US7", "description": "Jako pacjent chcę przeglądać historię moich poprzednich i nadchodzących wizyt wraz z ich statusami, aby mieć pełny wgląd w moje wizyty."}, {"id": "US8", "description": "Jako pacjent chcę otrzymać powiadomienie e-mail po dokonaniu, potwierdzeniu lub anulowaniu rezerwacji, aby być na bieżąco informowany o statusie mojej wizyty."}, {"id": "US9", "description": "Jako pacjent chcę otrzymać automatyczne przypomnienie e-mail o zbliżającej się wizycie, aby nie zapomnieć o zaplanowanym terminie."}, {"id": "US10", "description": "Jako pacjent chcę edytować dane swojego profilu, takie jak numer telefonu, adres e-mail i hasło, aby moje dane kontaktowe były zawsze aktualne."}, {"id": "US11", "description": "Jako specjalista chcę zdefiniować mój grafik dostępności, określając dni tygodnia i godziny przyjęć, aby pacjenci mogli rezerwować wizyty tylko w dostępnych terminach."}, {"id": "US12", "description": "Jako specjalista chcę zablokować wybrane terminy w moim grafiku, aby uniemożliwić rezerwację w czasie, gdy jestem niedostępny."}, {"id": "US13", "description": "Jako specjalista chcę przeglądać listę wszystkich zarezerwowanych wizyt w moim grafiku wraz z danymi pacjentów, aby być przygotowanym na nadchodzące wizyty."}, {"id": "US14", "description": "Jako specjalista chcę potwierdzić lub odwołać rezerwację dokonaną przez pacjenta, aby zarządzać moim harmonogramem i informować pacjentów o zmianach."}, {"id": "US15", "description": "Jako specjalista chcę otrzymać powiadomienie e-mail o nowej, anulowanej lub zmienionej rezerwacji, aby być na bieżąco informowany o zmianach w moim grafiku."}, {"id": "US16", "description": "Jako recepcjonista chcę dokonać rezerwacji wizyty w imieniu pacjenta, aby pomóc osobom, które nie mogą samodzielnie korzystać z systemu."}, {"id": "US17", "description": "Jako recepcjonista chcę anulować istniejącą rezerwację pacjenta, aby obsłużyć sytuacje, gdy pacjent zgłasza rezygnację osobiście lub telefonicznie."}, {"id": "US18", "description": "Jako recepcjonista chcę zarejestrować nowego pacjenta w systemie, aby umożliwić mu korzystanie z usług rezerwacji wizyt."}, {"id": "US19", "description": "Jako recepcjonista chcę przeglądać dostępne terminy wszystkich specjalistów, aby sprawnie odpowiadać na zapytania pacjentów i dokonywać rezerwacji."}, {"id": "US20", "description": "Jako administrator chcę zarządzać kontami wszystkich użytkowników, w tym tworzyć, edytować, dezaktywować i usuwać konta, aby utrzymać porządek i bezpieczeństwo w systemie."}, {"id": "US21", "description": "Jako administrator chcę przeglądać wszystkie rezerwacje w systemie, aby mieć pełny wgląd w aktywność użytkowników i obłożenie grafików specjalistów."}, {"id": "US22", "description": "Jako administrator chcę generować raporty dotyczące obłożenia grafików i aktywności użytkowników, aby podejmować decyzje oparte na danych."}, {"id": "US23", "description": "Jako administrator chcę zarządzać kategoriami i specjalizacjami specjalistów oraz przypisywać specjalistów do specjalizacji, aby utrzymać aktualną i spójną strukturę systemu."}, {"id": "US24", "description": "Jako administrator chcę anulować dowolną rezerwację w systemie, aby móc reagować na wyjątkowe sytuacje wymagające interwencji administracyjnej."}, {"id": "US25", "description": "Jako użytkownik systemu chcę mieć pewność, że wybrany przeze mnie termin zostanie natychmiast zablokowany po dokonaniu rezerwacji, aby uniknąć sytuacji, w której dwie osoby zarezerwują ten sam termin jednocześnie."}]

